const inputText = $input.first().json.body?.text || "";

const tasks = [];

const sentences = inputText
  .split(/[.!?]/)
  .map(s => s.trim())
  .filter(Boolean);

function detectPriority(sentence) {
  const text = sentence.toLowerCase();

  if (
    text.includes("urgent") ||
    text.includes("asap") ||
    text.includes("important") ||
    text.includes("high priority")
  ) {
    return "High";
  }

  if (
    text.includes("low priority") ||
    text.includes("whenever") ||
    text.includes("not urgent")
  ) {
    return "Low";
  }

  return "Medium";
}

function detectDeadline(sentence) {
  const text = sentence.toLowerCase();

  if (text.includes("today")) return "Today";
  if (text.includes("tomorrow")) return "Tomorrow";
  if (text.includes("next week")) return "Next week";

  const days = [
    "monday",
    "tuesday",
    "wednesday",
    "thursday",
    "friday",
    "saturday",
    "sunday"
  ];

  for (const day of days) {
    if (text.includes(day)) {
      return day.charAt(0).toUpperCase() + day.slice(1);
    }
  }

  const byMatch = sentence.match(/\bby\s+([A-Za-z0-9\s]+)/i);
  if (byMatch) return byMatch[1].trim();

  const beforeMatch = sentence.match(/\bbefore\s+([A-Za-z0-9\s]+)/i);
  if (beforeMatch) return beforeMatch[1].trim();

  return "Not specified";
}

function cleanTask(task) {
  return task
    .replace(/\bby today\b/gi, "")
    .replace(/\btoday\b/gi, "")
    .replace(/\bby tomorrow\b/gi, "")
    .replace(/\btomorrow\b/gi, "")
    .replace(/\bby monday\b/gi, "")
    .replace(/\bby tuesday\b/gi, "")
    .replace(/\bby wednesday\b/gi, "")
    .replace(/\bby thursday\b/gi, "")
    .replace(/\bby friday\b/gi, "")
    .replace(/\bby saturday\b/gi, "")
    .replace(/\bby sunday\b/gi, "")
    .replace(/\bbefore monday\b/gi, "")
    .replace(/\bbefore tuesday\b/gi, "")
    .replace(/\bbefore wednesday\b/gi, "")
    .replace(/\bbefore thursday\b/gi, "")
    .replace(/\bbefore friday\b/gi, "")
    .replace(/\bbefore saturday\b/gi, "")
    .replace(/\bbefore sunday\b/gi, "")
    .replace(/\bnext week\b/gi, "")
    .replace(/\burgent\b/gi, "")
    .replace(/\basap\b/gi, "")
    .replace(/\bimportant\b/gi, "")
    .replace(/\bhigh priority\b/gi, "")
    .replace(/\blow priority\b/gi, "")
    .replace(/\s+/g, " ")
    .trim();
}

function isOnlyPrioritySentence(sentence) {
  const text = sentence.toLowerCase().trim();

  return (
    text === "it is urgent" ||
    text === "this is urgent" ||
    text === "urgent" ||
    text === "it is important" ||
    text === "this is important" ||
    text === "high priority" ||
    text === "this is high priority" ||
    text === "asap"
  );
}

for (const sentence of sentences) {
  // If sentence only tells priority, apply it to previous task
  if (isOnlyPrioritySentence(sentence)) {
    if (tasks.length > 0) {
      tasks[tasks.length - 1].priority = detectPriority(sentence);
    }
    continue;
  }

  let owner = "Unassigned";
  let task = sentence;

  // Pattern: Sara needs to send...
  let match = sentence.match(/^([A-Z][a-z]+)\s+(needs to|should|must|has to|will|was asked to)\s+(.+)/i);

  if (match) {
    owner = match[1];
    task = match[3];
  }

  // Pattern: assign Sara to send...
  let assignMatch = sentence.match(/assign\s+([A-Z][a-z]+)\s+to\s+(.+)/i);

  if (assignMatch) {
    owner = assignMatch[1];
    task = assignMatch[2];
  }

  const cleanedTask = cleanTask(task);

  // Avoid adding empty/useless task
  if (!cleanedTask || cleanedTask.length < 3) {
    continue;
  }

  tasks.push({
    task: cleanedTask,
    owner,
    deadline: detectDeadline(sentence),
    priority: detectPriority(sentence)
  });
}

return [
  {
    json: {
      success: true,
      tasks
    }
  }
];
